from langgraph.graph import StateGraph, END
from langgraph.types import Send
from typing import TypedDict, Annotated
import operator

MAX_WORKERS = 5

class ManagerState(TypedDict):
    tasks: list[dict]          # [{id, payload}, ...]
    results: Annotated[list[dict], operator.add]
    errors:  Annotated[list[str],  operator.add]
    final:   str

class WorkerState(TypedDict):
    task_id: str
    payload: str
    result:  str
    errors:  list[str]

def manager_node(state: ManagerState) -> dict:
    """No-op: tasks are already in state from the caller."""
    return {}

def dispatch_batch(state: ManagerState) -> list[Send]:
    """Fan-out all tasks, up to MAX_WORKERS at once per LangGraph execution."""
    completed_ids = {r["task_id"] for r in state["results"]}
    pending = [t for t in state["tasks"] if t["id"] not in completed_ids]
    # LangGraph runs all Sends concurrently; Semaphore can throttle externally
    return [
        Send("worker", {
            "task_id": t["id"],
            "payload": t["payload"],
            "result":  "",
            "errors":  [],
        })
        for t in pending[:MAX_WORKERS]
    ]

def worker_node(state: WorkerState) -> dict:
    try:
        resp = llm.invoke([
            {"role": "system", "content": "Summarise in one sentence."},
            {"role": "user",   "content": state["payload"]},
        ])
        return {"result": resp.content, "task_id": state["task_id"], "errors": []}
    except Exception as exc:
        return {"result": "", "task_id": state["task_id"], "errors": [f"{state['task_id']}:{exc}"]}

def aggregate_node(state: ManagerState) -> dict:
    outputs = [r["result"] for r in state["results"] if r.get("result")]
    return {"final": "\n".join(outputs)}

def has_pending(state: ManagerState) -> str:
    completed_ids = {r["task_id"] for r in state["results"]}
    pending = [t for t in state["tasks"] if t["id"] not in completed_ids]
    return "dispatch" if pending else "aggregate"
